import{_ as a,o as e,c as l,ag as r}from"./chunks/framework.CxZWPeXl.js";const b=JSON.parse('{"title":"知識助手","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/knowledge-assistant.md","filePath":"zh-TW/knowledge-assistant.md"}'),i={name:"zh-TW/knowledge-assistant.md"};function d(o,t,h,n,s,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="知識助手" tabindex="-1">知識助手 <a class="header-anchor" href="#知識助手" aria-label="Permalink to &quot;知識助手&quot;">​</a></h1><blockquote><p>隨時查詢銷售知識，為你的對話練習提供專業後盾</p></blockquote><h2 id="概覽" tabindex="-1">概覽 <a class="header-anchor" href="#概覽" aria-label="Permalink to &quot;概覽&quot;">​</a></h2><p>知識助手是 AI Coach 內建的智慧問答功能，基於 RAG（檢索增強生成）技術，能從公司知識庫中檢索相關資料並產生精準回答。您可以在練習前、中、後隨時使用，補充銷售知識與話術技巧。</p><h2 id="開啟方式" tabindex="-1">開啟方式 <a class="header-anchor" href="#開啟方式" aria-label="Permalink to &quot;開啟方式&quot;">​</a></h2><p>點擊頁面右上方導覽列中的 <strong>知識助手圖示</strong> 即可開啟。</p><blockquote><p>此功能需要具備知識庫閱讀權限。如果看不到圖示，請聯繫管理員確認權限設定。</p></blockquote><hr><h2 id="介面說明" tabindex="-1">介面說明 <a class="header-anchor" href="#介面說明" aria-label="Permalink to &quot;介面說明&quot;">​</a></h2><h3 id="標題列" tabindex="-1">標題列 <a class="header-anchor" href="#標題列" aria-label="Permalink to &quot;標題列&quot;">​</a></h3><table tabindex="0"><thead><tr><th>元素</th><th>說明</th></tr></thead><tbody><tr><td>AI Logo</td><td>知識助手的辨識圖示</td></tr><tr><td>AI Chat</td><td>標題文字</td></tr><tr><td>連線狀態</td><td>綠色圓點「線上」表示可正常使用；紅色圓點「離線」表示暫時無法使用</td></tr><tr><td>清除對話</td><td>清除所有對話紀錄，重新開始</td></tr></tbody></table><h3 id="對話區域" tabindex="-1">對話區域 <a class="header-anchor" href="#對話區域" aria-label="Permalink to &quot;對話區域&quot;">​</a></h3><table tabindex="0"><thead><tr><th>元素</th><th>說明</th></tr></thead><tbody><tr><td>歡迎畫面</td><td>首次開啟時顯示，提供使用引導</td></tr><tr><td>訊息列表</td><td>您的問題（右側）與 AI 回答（左側）的對話紀錄</td></tr><tr><td>打字指示器</td><td>AI 正在產生回答時顯示的動畫效果</td></tr></tbody></table><h3 id="快速問答卡片-suggested-questions" tabindex="-1">快速問答卡片 (Suggested Questions) <a class="header-anchor" href="#快速問答卡片-suggested-questions" aria-label="Permalink to &quot;快速問答卡片 (Suggested Questions)&quot;">​</a></h3><p>進入後可直接點擊系統建議的標籤丸：</p><ul><li><strong>保險新知</strong>：查詢產業最新趨勢與新聞</li><li><strong>保險問答大補帖</strong>：常用話術與客戶 Q&amp;A 參考</li><li><strong>保險業務人員的專業新知</strong>：專業知識與深度見解</li><li><strong>心理學在保險業務中的應用</strong>：銷售心理學實務應用</li></ul><h3 id="輸入區" tabindex="-1">輸入區 <a class="header-anchor" href="#輸入區" aria-label="Permalink to &quot;輸入區&quot;">​</a></h3><ul><li>輸入框：「輸入您的問題...」</li><li>支援 <strong>Enter</strong> 送出以及 <strong>Shift+Enter</strong> 換行輸入</li><li>傳送按鈕：點擊送出問題（AI 回答中時暫時停用）</li></ul><hr><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><ol><li>點擊知識助手圖示開啟聊天視窗</li><li>在輸入框中輸入您的問題</li><li>點擊傳送或按 Enter 送出</li><li>等待 AI 從知識庫中檢索資料並產生回答</li><li>查看回答內容，如需進一步了解可繼續提問</li></ol><h2 id="適用場景" tabindex="-1">適用場景 <a class="header-anchor" href="#適用場景" aria-label="Permalink to &quot;適用場景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>場景</th><th>問題範例</th></tr></thead><tbody><tr><td>產品查詢</td><td>「XX保險的保障範圍有哪些？」</td></tr><tr><td>話術參考</td><td>「面對擔心保費太高的客戶，有什麼建議的話術？」</td></tr><tr><td>規範查詢</td><td>「理賠申請的流程是什麼？」</td></tr><tr><td>比較分析</td><td>「A 方案和 B 方案的差異在哪裡？」</td></tr><tr><td>常見問題</td><td>「客戶最常問的前三個問題是什麼？」</td></tr></tbody></table><h2 id="注意事項" tabindex="-1">注意事項 <a class="header-anchor" href="#注意事項" aria-label="Permalink to &quot;注意事項&quot;">​</a></h2><ul><li>知識助手的回答品質取決於管理員上傳的知識庫內容</li><li>回答僅供參考，實際銷售時請以公司正式文件與最新規範為準</li><li>對話紀錄儲存在本地瀏覽器中，清除瀏覽器資料後會消失</li><li>切換帳號或清除對話後，歷史紀錄不會保留</li></ul><hr><h2 id="與對話練習的搭配" tabindex="-1">與對話練習的搭配 <a class="header-anchor" href="#與對話練習的搭配" aria-label="Permalink to &quot;與對話練習的搭配&quot;">​</a></h2><h3 id="練習前" tabindex="-1">練習前 <a class="header-anchor" href="#練習前" aria-label="Permalink to &quot;練習前&quot;">​</a></h3><ul><li>查詢即將練習的客戶類型常見需求</li><li>了解對應的保險產品特色與賣點</li><li>準備應對可能的異議與問題</li></ul><h3 id="練習後" tabindex="-1">練習後 <a class="header-anchor" href="#練習後" aria-label="Permalink to &quot;練習後&quot;">​</a></h3><ul><li>針對評量報告指出的弱項查詢相關知識</li><li>學習更好的話術與應對策略</li><li>補強特定銷售階段的知識</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>開始 <a href="./practice.html">對話練習</a> 實際運用學到的知識</li><li>查看 <a href="./evaluation.html">評量報告</a> 找出需要補強的方向</li></ul>',34)])])}const q=a(i,[["render",d]]);export{b as __pageData,q as default};
